            {tool.imageOrPrompt && (
              <div className="ai-tool__output-mode-toggle">
                <button
                  type="button"
                  className={`ai-tool__mode-btn${outputMode === 'image' ? ' active' : ''}`}
                  onClick={() => setOutputMode('image')}
                >
                  🖼 Generate Image
                </button>
                <button
                  type="button"
                  className={`ai-tool__mode-btn${outputMode === 'prompt' ? ' active' : ''}`}
                  onClick={() => setOutputMode('prompt')}
                >
