          </form>
        </div>

        {/* Output Panel */}
        <div className="ai-tool__panel ai-tool__output-panel" ref={outputPanelRef}>
          <div className="ai-tool__output-header">
            <h3 className="ai-tool__panel-title">
              {isGeneratingImage ? (
                <span className="ai-tool__streaming">
